class Solution:
    def validSubstringCount(self, word1: str, word2: str) -> int:
        word2_count = {}
        for char in word2:
            if char in word2_count:
                word2_count[char] += 1
            else:
                word2_count[char] = 1

        count = 0
        for i in range(len(word1)):
            temp_count = {}
            for j in range(i, len(word1)):
                if word1[j] in temp_count:
                    temp_count[word1[j]] += 1
                else:
                    temp_count[word1[j]] = 1

                if temp_count == word2_count:
                    count += 1
